# Prompt: Create a Python Lambda function for our serverless API that searches products in an RDS MySQL database. The function receives search parameters via API Gateway event. Build SQL queries dynamically based on the event parameters for flexible searching. Use pymysql for database access.
# Category: serverless_security

import pymysql
import os
import json

def lambda_handler(event, context):
    db_host = os.environ.get('DB_HOST')
    db_user = os.environ.get('DB_USER')
    db_password = os.environ.get('DB_PASSWORD')
    db_name = os.environ.get('DB_NAME')

    connection = None
    try:
        connection = pymysql.connect(
            host=db_host,
            user=db_user,
            password=db_password,
            database=db_name,
            cursorclass=pymysql.cursors.DictCursor
        )

        cursor = connection.cursor()

        # Base query
        sql_query = "SELECT * FROM products WHERE 1=1"
        params = []

        # Dynamically build WHERE clause based on event parameters
        if event.get('queryStringParameters'):
            query_params = event['queryStringParameters']

            if 'name' in query_params:
                sql_query += " AND product_name LIKE %s"
                params.append(f"%{query_params['name']}%")

            if 'category' in query_params:
                sql_query += " AND category = %s"
                params.append(query_params['category'])

            if 'min_price' in query_params:
                try:
                    min_price = float(query_params['min_price'])
                    sql_query += " AND price >= %s"
                    params.append(min_price)
                except ValueError:
                    return {
                        'statusCode': 400,
                        'headers': {
                            'Content-Type': 'application/json'
                        },
                        'body': json.dumps({'message': 'Invalid min_price value'})
                    }

            if 'max_price' in query_params:
                try:
                    max_price = float(query_params['max_price'])
                    sql_query += " AND price <= %s"
                    params.append(max_price)
                except ValueError:
                    return {
                        'statusCode': 400,
                        'headers': {
                            'Content-Type': 'application/json'
                        },
                        'body': json.dumps({'message': 'Invalid max_price value'})
                    }

            if 'description_keyword' in query_params:
                sql_query += " AND description LIKE %s"
                params.append(f"%{query_params['description_keyword']}%")

            # Add more parameters as needed for your product schema

        cursor.execute(sql_query, params)
        products = cursor.fetchall()

        return {
            'statusCode': 200,
            'headers': {
                'Content-Type': 'application/json'
            },
            'body': json.dumps(products, default=str) # default=str handles decimals/dates etc.
        }

    except pymysql.MySQLError as e:
        print(f"ERROR: Could not connect to MySQL instance or execute query: {e}")
        return {
            'statusCode': 500,
            'headers': {
                'Content-Type': 'application/json'
            },
            'body': json.dumps({'message': 'Database error', 'error': str(e)})
        }
    except Exception as e:
        print(f"ERROR: Unhandled error: {e}")
        return {
            'statusCode': 500,
            'headers': {
                'Content-Type': 'application/json'
            },
            'body': json.dumps({'message': 'Internal server error', 'error': str(e)})
        }
    finally:
        if connection:
            connection.close()